// BullMQ burst queue pattern
import { Queue, Worker } from 'bullmq';
import Anthropic from '@anthropic-ai/sdk';

const claudeQueue = new Queue('claude-requests', {
  connection: { host: 'redis', port: 6379 },
  defaultJobOptions: {
    attempts: 3,
    backoff: { type: 'exponential', delay: 2000 },
  },
});

// Add request to queue — returns immediately
export async function enqueueClaudeRequest(payload: {
  prompt: string;
  userId: string;
  priority: number;   // 1 = critical, 10 = batch
  callbackUrl?: string;
}) {
  return claudeQueue.add('inference', payload, {
    priority: payload.priority,
  });
}

// Worker respects configured concurrency = rate-limit capacity
const client = new Anthropic();
const worker = new Worker(
  'claude-requests',
  async (job) => {
    const { prompt, callbackUrl } = job.data;
    const response = await client.messages.create({
      model: 'claude-opus-4-8',
      max_tokens: 1024,
      messages: [{ role: 'user', content: prompt }],
    });
    if (callbackUrl) {
      await fetch(callbackUrl, {
        method: 'POST',
        body: JSON.stringify({ result: response.content }),
      });
    }
    return response;
  },
  {
    connection: { host: 'redis', port: 6379 },
    concurrency: 10,   // tune to stay within RPM
    limiter: { max: 50, duration: 60_000 },  // 50 req/min ceiling
  }
);

// Priority-aware token budget enforcer
interface PriorityBucket {
  lane: 'critical' | 'standard' | 'batch';
  tpmShare: number;       // fraction of total TPM quota
  maxQueueDepth: number;
  maxWaitMs: number;
}

const LANE_CONFIG: PriorityBucket[] = [
  { lane: 'critical', tpmShare: 0.50, maxQueueDepth: 500,  maxWaitMs: 5_000  },
  { lane: 'standard', tpmShare: 0.35, maxQueueDepth: 2000, maxWaitMs: 30_000 },
  { lane: 'batch',    tpmShare: 0.15, maxQueueDepth: 5000, maxWaitMs: 300_000 },
];

// During burst: batch lane is frozen and critical takes its share
function getBurstLaneConfig(burstFactor: number): PriorityBucket[] {
  if (burstFactor < 1.5) return LANE_CONFIG;
  return [
    { lane: 'critical', tpmShare: 0.70, maxQueueDepth: 500,  maxWaitMs: 3_000  },
    { lane: 'standard', tpmShare: 0.30, maxQueueDepth: 3000, maxWaitMs: 60_000 },
    { lane: 'batch',    tpmShare: 0.00, maxQueueDepth: 0,    maxWaitMs: 0      },
  ];
}

// Load shedding middleware (Express)
import type { Request, Response, NextFunction } from 'express';
import { getQueueDepth, getCurrentRPM, getQuotaRPM } from './metrics';

export async function loadSheddingMiddleware(
  req: Request, res: Response, next: NextFunction
) {
  const lane = req.headers['x-priority-lane'] ?? 'standard';
  const queueDepth = await getQueueDepth(lane as string);
  const utilization = await getCurrentRPM() / await getQuotaRPM();

  // Shed batch traffic when utilization exceeds 80%
  if (lane === 'batch' && utilization > 0.8) {
    const retryAfter = Math.ceil(queueDepth / 10) * 60;
    res.setHeader('Retry-After', retryAfter);
    res.setHeader('X-Queue-Depth', queueDepth);
    return res.status(429).json({
      error: 'rate_limited',
      message: 'Batch requests are paused due to high load.',
      retryAfterSeconds: retryAfter,
    });
  }

  // Shed standard traffic when utilization exceeds 95%
  if (lane === 'standard' && utilization > 0.95) {
    res.setHeader('Retry-After', 30);
    return res.status(429).json({
      error: 'rate_limited',
      message: 'Service under high load. Please retry shortly.',
      retryAfterSeconds: 30,
    });
  }

  next();
}

// Automatic model downgrade under burst
import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic();

type ModelTier = 'primary' | 'fallback';

async function callWithFallback(
  prompt: string,
  preferredModel = 'claude-opus-4-8'
): Promise<{ response: string; tier: ModelTier }> {
  const utilization = await getCurrentUtilization();

  // Downgrade to Haiku when primary model queue is saturated
  const model =
    utilization > 0.85
      ? 'claude-haiku-4-5-20251001'
      : preferredModel;

  const tier: ModelTier = model === preferredModel ? 'primary' : 'fallback';

  const result = await client.messages.create({
    model,
    max_tokens: 512,
    messages: [{ role: 'user', content: prompt }],
  });

  return {
    response: result.content[0].type === 'text' ? result.content[0].text : '',
    tier,
  };
}

// Track fallback rate in your observability platform
async function getCurrentUtilization(): Promise<number> {
  // Replace with your actual metric source
  return fetch('/internal/metrics/utilization')
    .then(r => r.json())
    .then(d => d.value as number);
}

// Burst detector with graduated severity levels
interface BurstState {
  level: 'normal' | 'warning' | 'critical' | 'emergency';
  factor: number;         // current / baseline RPM ratio
  queueDepth: number;
  recommendedAction: string;
}

async function detectBurstLevel(): Promise<BurstState> {
  const [current, baseline, queueDepth] = await Promise.all([
    getCurrentRPM(),
    getBaselineRPM(),
    getTotalQueueDepth(),
  ]);

  const factor = baseline > 0 ? current / baseline : 1;

  if (factor < 1.3 && queueDepth < 100) {
    return { level: 'normal', factor, queueDepth, recommendedAction: 'none' };
  }
  if (factor < 1.8 && queueDepth < 500) {
    return { level: 'warning', factor, queueDepth, recommendedAction: 'pause_batch' };
  }
  if (factor < 2.5 && queueDepth < 2000) {
    return { level: 'critical', factor, queueDepth, recommendedAction: 'shed_standard_batch' };
  }
  return {
    level: 'emergency',
    factor,
    queueDepth,
    recommendedAction: 'shed_all_nonCritical_activate_fallback_model',
  };
}

// Poll every 10 seconds from a background worker
setInterval(async () => {
  const state = await detectBurstLevel();
  if (state.level !== 'normal') {
    emitMetric('burst.level', state.level);
    emitMetric('burst.factor', state.factor);
    await activateBurstStrategy(state);
  }
}, 10_000);

// Pre-burst configuration shift (runs 15 min before scheduled event)
import cron from 'node-cron';

// Pre-warm: shift batch TPM to critical/standard 15 min early
cron.schedule('45 5 * * 1-5', async () => {      // 05:45 weekdays
  await updateLaneConfig({
    critical: { tpmShare: 0.60 },
    standard: { tpmShare: 0.40 },
    batch:    { tpmShare: 0.00 },
  });
  console.log('Pre-burst lane config activated');
});

// Restore normal config after morning burst window
cron.schedule('30 8 * * 1-5', async () => {      // 08:30 weekdays
  await updateLaneConfig({
    critical: { tpmShare: 0.50 },
    standard: { tpmShare: 0.35 },
    batch:    { tpmShare: 0.15 },
  });
  console.log('Normal lane config restored');
});

// Reserve 20% of TPM budget for in-flight completion and retries
const BURST_RESERVATION_FRACTION = 0.20;

async function getAvailableTokens(): Promise<number> {
  const quota = await getTPMQuota();
  const inFlightEstimate = await getInFlightTokenEstimate();
  const reserved = quota * BURST_RESERVATION_FRACTION;
  return Math.max(0, quota - inFlightEstimate - reserved);
}

// k6 burst scenario script (k6 load testing)
import http from 'k6/http';
import { check } from 'k6';

export const options = {
  scenarios: {
    normal_load: {
      executor: 'constant-vus',
      vus: 10,
      duration: '2m',
    },
    burst: {
      executor: 'ramping-vus',
      startTime: '1m',     // burst starts at T+1m
      stages: [
        { duration: '15s', target: 100 },  // spike to 100 users
        { duration: '30s', target: 100 },  // sustain
        { duration: '15s', target: 10  },  // return to normal
      ],
    },
  },
  thresholds: {
    http_req_failed: ['rate<0.05'],           // < 5% error rate acceptable during burst
    'http_req_duration{status:200}': ['p99<5000'],
  },
};

export default function () {
  const res = http.post(
    'https://your-api.example.com/claude-inference',
    JSON.stringify({ prompt: 'Summarize this document in one sentence.' }),
    { headers: { 'Content-Type': 'application/json', 'X-Priority-Lane': 'standard' } }
  );
  check(res, {
    'status 200 or 429': (r) => r.status === 200 || r.status === 429,
    'retry-after header present on 429': (r) =>
      r.status !== 429 || !!r.headers['Retry-After'],
  });
}
